UPDATE mq_message_log
status = #{status}, error_message = #{errorMessage}, result_snapshot = #{resultSnapshotJson}::jsonb, processed_at = NOW()
WHERE id = #{id}

UPDATE mq_message_log
retry_count = retry_count + 1, status = #{status}, error_message = #{errorMessage}, processed_at = CASE WHEN #{status} = 'FAILED' THEN NOW() ELSE processed_at END
WHERE id = #{id}
